const formatBRL2 = (v) =>
  new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL", minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(v);

const formatBRL = (v) =>
  new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL", maximumFractionDigits: 0 }).format(v);

const formatPct = (v) => v != null ? `${v >= 0 ? "+" : ""}${v.toFixed(1)}%` : "—";

const diasNoMes = (ano, mes) => new Date(ano, mes, 0).getDate();

// Retorna a série do mês: array de {dia, valor, meta} com 0 pra dias não preenchidos
const getSerie = (ano, mes) => {
  const dados = DADOS_ASSINATURAS[`${ano}-${mes}`] || [];
  const dias = diasNoMes(ano, mes);
  const serie = [];
  for (let d = 1; d <= dias; d++) {
    const row = dados.find((r) => r[0] === d);
    serie.push({
      dia: d,
      valor: row ? row[1] : 0,
      meta: row ? row[2] : 0,
    });
  }
  return serie;
};

// Retorna meta mensal.
// Regra: em 2026, meta = total do mesmo mês de 2025 × 1,20 (crescimento de 20%).
// Nos demais anos, usa o valor da planilha: max(day1_value, sum_other_days).
const getMetaMensal = (ano, mes) => {
  if (ano === 2026) {
    const serieAnt = getSerie(2025, mes);
    const totalAnt = serieAnt.reduce((a, b) => a + b.valor, 0);
    return totalAnt * 1.2;
  }
  const serie = getSerie(ano, mes);
  if (serie.length === 0) return 0;
  const dia1 = serie[0].meta;
  const outros = serie.slice(1).reduce((a, b) => a + b.meta, 0);
  return Math.max(dia1, outros);
};

// Acumulado até dia X
const acumuladoAte = (serie, diaCorte) =>
  serie.slice(0, diaCorte).reduce((a, b) => a + b.valor, 0);

// Soma os valores da série dentro do período [inicio, fim] (1-indexado, inclusivo)
const acumuladoPeriodo = (serie, inicio, fim) =>
  serie.slice(Math.max(0, inicio - 1), fim).reduce((a, b) => a + b.valor, 0);

// Conta dias com valor > 0 dentro do período (dias de operação efetiva)
const diasOperacaoPeriodo = (serie, inicio, fim) =>
  serie.slice(Math.max(0, inicio - 1), fim).filter((d) => d.valor > 0).length;

// Verifica se há dados reais para ano-mês
const temDados = (ano, mes) => {
  const dados = DADOS_ASSINATURAS[`${ano}-${mes}`];
  if (!dados) return false;
  return dados.some((r) => r[1] > 0);
};

// Último dia com dado real
const ultimoDiaComDado = (ano, mes) => {
  const dados = DADOS_ASSINATURAS[`${ano}-${mes}`] || [];
  let ultimo = 0;
  dados.forEach((r) => {
    if (r[1] > 0) ultimo = Math.max(ultimo, r[0]);
  });
  return ultimo;
};

